script:
class CRMLead {
  async onRender() { await this.doc.trigger("_renderForschPanel"); }
  async _renderForschPanel() {
    if (!this.doc || !this.doc.name) return;
    let res = {};
    try {
      res = await this.call("forsch_frontiers.api.parity.related_records",
        { anchor_doctype: "CRM Lead", anchor_name: this.doc.name });
    } catch (e) { res = {}; }
    const data = (res && res.message) ? res.message : (res || {});
    const labels = { newsletterSubscription: "Newsletter", touch: "Social Touch", lbActivity: "Littlebird" };
    const colors = { Active: "#16a34a", Unsubscribed: "#9ca3af", Bounced: "#dc2626" };
    let cards = ""; let total = 0;
    for (const k of Object.keys(data || {})) {
      for (const it of (data[k] || [])) {
        total++;
        const c = colors[it.status] || "#6b7280";
        cards += `<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;border:1px solid #ececec;border-radius:8px;margin-bottom:6px;background:#fff">`
          + `<div><div style="font-weight:600;font-size:13px;color:#111">${it.audience_title || it.title || it.name}</div>`
          + `<div style="font-size:11px;color:#9ca3af;margin-top:2px">${labels[k] || k}</div></div>`
          + `<span style="font-size:11px;font-weight:600;color:${c}">${it.status || ""}</span></div>`;
      }
    }
    const html = total
      ? cards
      : `<div style="font-size:12px;color:#9ca3af;padding:6px 2px">No linked Forsch records yet.</div>`;
    this.setFieldHtml("ff_related_records_html", html);
  }
}
